+function findParentNode(
+	node: AgentTreeNode,
+	agentId: string,
+	parent?: AgentTreeNode,
+): AgentTreeNode | undefined {
+	if (node.agentId === agentId) {
+		return parent;
+	}
+	for (const child of node.children) {
+		const found = findParentNode(child, agentId, node);
+		if (found) {
+			return found;
+		}
+	}
+	return undefined;
+}
